import { useState } from 'react';

const useRideRequest = () => {
  const [requesting, setRequesting] = useState(false);

  const requestRide = () => {
    setRequesting(true);
    // Simulate API call
    setTimeout(() => {
      setRequesting(false);
      alert('Ride requested successfully!');
    }, 2000);
  };

  return { requesting, requestRide };
};

export default useRideRequest;

